DOSSIER   = Path(r"C:\python")
CSV_PATH  = DOSSIER / "BCASAD.CSV"
HTML_PATH = DOSSIER / "bourse_casablanca.html"
SEP = "=" * 62

def log(m): print("  " + m)

# ── Indicateurs techniques ──────────────────────────────────
def calc_ma(data, p):
    r=[None]*len(data)
    for i in range(p-1,len(data)): r[i]=round(sum(data[i-p+1:i+1])/p,2)
    return r

def calc_ema(data, p):
    r=[None]*len(data); k=2/(p+1); prev=None
    for i in range(len(data)):
        if data[i] is None: continue
        if prev is None:
            if i>=p-1:
                vs=[data[j] for j in range(i-p+1,i+1)]
                if all(v is not None for v in vs): prev=sum(vs)/p; r[i]=round(prev,2)
        else: prev=data[i]*k+prev*(1-k); r[i]=round(prev,2)
    return r

def calc_rsi(closes, p=14):
    n=len(closes); r=[None]*n
    if n<p+1: return r
    g=[max(0,closes[i]-closes[i-1]) for i in range(1,p+1)]
    l=[max(0,closes[i-1]-closes[i]) for i in range(1,p+1)]
    ag=sum(g)/p; al=sum(l)/p
    r[p]=round(100-100/(1+(ag/al if al>0 else 100)),2)
    for i in range(p+1,n):
        d=closes[i]-closes[i-1]
        ag=(ag*13+max(0,d))/14; al=(al*13+max(0,-d))/14
        r[i]=round(100-100/(1+(ag/al if al>0 else 100)),2)
    return r

# ── Indicateurs avances (robustes meme si high=low=close) ───
def _hl_robuste(ss, p=14):
    """Retourne (highs, lows) utilisables. Si high==low==close (frequent
    dans le CSV BVC), reconstruit une fourchette glissante a partir des
    cloture pour ne pas degenerer les oscillateurs."""
    closes=[s["close"] for s in ss]
    highs =[s.get("high",s["close"]) for s in ss]
    lows  =[s.get("low", s["close"]) for s in ss]
    plats=sum(1 for i in range(len(ss)) if highs[i]==lows[i]==closes[i])
    # Si plus de 60% des seances sont "plates", on derive H/L des clotures
    if len(ss) and plats/len(ss) > 0.6:
        rh=list(closes); rl=list(closes)
        for i in range(len(closes)):
            j0=max(0,i-2); win=closes[j0:i+1]
            rh[i]=max(highs[i],max(win)); rl[i]=min(lows[i],min(win))
        return rh, rl
    return highs, lows

def calc_stoch(highs, lows, closes, p=14, d=3):
    n=len(closes); k=[None]*n
    for i in range(p-1,n):
        hh=max(highs[i-p+1:i+1]); ll=min(lows[i-p+1:i+1])
        k[i]=round((closes[i]-ll)/(hh-ll)*100,2) if hh>ll else 50.0
    dd=[None]*n
    for i in range(p-1+d-1,n):
        w=[k[j] for j in range(i-d+1,i+1) if k[j] is not None]
        if len(w)==d: dd[i]=round(sum(w)/d,2)
    return k,dd

def calc_atr(highs, lows, closes, p=14):
    n=len(closes)
    if n==0: return []
    tr=[highs[0]-lows[0]]
    for i in range(1,n):
        tr.append(max(highs[i]-lows[i], abs(highs[i]-closes[i-1]), abs(lows[i]-closes[i-1])))
    atr=[None]*n
    if n>=p:
        prev=sum(tr[:p])/p; atr[p-1]=round(prev,3)
        for i in range(p,n):
            prev=(prev*(p-1)+tr[i])/p; atr[i]=round(prev,3)
    return atr

def calc_obv(closes, vols):
    n=len(closes); obv=[0]*n
    for i in range(1,n):
        if closes[i]>closes[i-1]:   obv[i]=obv[i-1]+(vols[i] or 0)
        elif closes[i]<closes[i-1]: obv[i]=obv[i-1]-(vols[i] or 0)
        else:                       obv[i]=obv[i-1]
    return obv

def calc_williams(highs, lows, closes, p=14):
    n=len(closes); r=[None]*n
    for i in range(p-1,n):
        hh=max(highs[i-p+1:i+1]); ll=min(lows[i-p+1:i+1])
        r[i]=round((hh-closes[i])/(hh-ll)*-100,2) if hh>ll else -50.0
    return r

def calc_roc(closes, p=12):
    n=len(closes); r=[None]*n
    for i in range(p,n):
        r[i]=round((closes[i]-closes[i-p])/closes[i-p]*100,2) if closes[i-p] else None
    return r

def calc_cci(highs, lows, closes, p=20):
    n=len(closes); r=[None]*n
    tp=[(highs[i]+lows[i]+closes[i])/3 for i in range(n)]
    for i in range(p-1,n):
        w=tp[i-p+1:i+1]; ma=sum(w)/p
        md=sum(abs(x-ma) for x in w)/p
        r[i]=round((tp[i]-ma)/(0.015*md),2) if md>0 else 0.0
    return r

def calc_pivots(h,l,c):
    if not (h and l and c): return {}
    pp=(h+l+c)/3
    return {"pp":round(pp,2),"r1":round(2*pp-l,2),"s1":round(2*pp-h,2),
            "r2":round(pp+(h-l),2),"s2":round(pp-(h-l),2),
            "r3":round(h+2*(pp-l),2),"s3":round(l-2*(h-pp),2)}

def calc_max_drawdown(closes):
    if not closes: return None
    peak=closes[0]; mdd=0.0
    for c in closes:
        if c>peak: peak=c
        dd=(c-peak)/peak*100 if peak else 0
        if dd<mdd: mdd=dd
    return round(mdd,2)

def calc_beta(asset_ret, market_ret):
    pairs=[(a,m) for a,m in zip(asset_ret,market_ret)
           if a is not None and m is not None]
    if len(pairs)<30: return None
    n=len(pairs); ma=sum(a for a,_ in pairs)/n; mm=sum(m for _,m in pairs)/n
    cov=sum((a-ma)*(m-mm) for a,m in pairs)/n
    var=sum((m-mm)**2 for _,m in pairs)/n
    return round(cov/var,2) if var>0 else None

def calc_sortino(returns, target=0.0):
    r=[x for x in returns if x is not None]
    if len(r)<10: return None
    mean=sum(r)/len(r)
    dn=[min(0.0,x-target)**2 for x in r]
    dd=(sum(dn)/len(r))**0.5
    return round(mean/dd,3) if dd>0 else None

def calc_indicators(ss):
    closes=[s["close"] for s in ss]; n=len(closes)
    vols=[s.get("volume",0) for s in ss]
    highs,lows=_hl_robuste(ss,14)
    mm20=calc_ma(closes,20); mm50=calc_ma(closes,50); mm200=calc_ma(closes,200)
    rsi=calc_rsi(closes,14)
    ema12=calc_ema(closes,12); ema26=calc_ema(closes,26)
    macd=[round(a-b,3) if a and b else None for a,b in zip(ema12,ema26)]
    signal=calc_ema(macd,9)
    histo=[round(a-b,3) if a and b else None for a,b in zip(macd,signal)]
    bbu=[None]*n; bbl=[None]*n
    for i in range(19,n):
        w=closes[i-19:i+1]; mu=sum(w)/20; sd=(sum((x-mu)**2 for x in w)/20)**0.5
        bbu[i]=round(mu+2*sd,2); bbl[i]=round(mu-2*sd,2)
    stoch_k,stoch_d=calc_stoch(highs,lows,closes,14,3)
    atr=calc_atr(highs,lows,closes,14)
    obv=calc_obv(closes,vols)
    will_r=calc_williams(highs,lows,closes,14)
    roc=calc_roc(closes,12)
    cci=calc_cci(highs,lows,closes,20)
    return {"mm20":mm20,"mm50":mm50,"mm200":mm200,"rsi":rsi,
            "macd":macd,"signal":signal,"histogram":histo,"bb_upper":bbu,"bb_lower":bbl,
            "stoch_k":stoch_k,"stoch_d":stoch_d,"atr":atr,"obv":obv,
            "will_r":will_r,"roc":roc,"cci":cci}

def interpret(ss, ind):
    closes=[s["close"] for s in ss]; c=closes[-1]; sigs=[]; score=0
    lm20=next((v for v in reversed(ind["mm20"]) if v),None)
    lm50=next((v for v in reversed(ind["mm50"]) if v),None)
    lm200=next((v for v in reversed(ind["mm200"]) if v),None)
    if lm20:
        if c>lm20: sigs.append({"ind":"MM20","msg":"Cours au-dessus de la MM20","sens":"positif"}); score+=1
        else: sigs.append({"ind":"MM20","msg":"Cours en-dessous de la MM20","sens":"negatif"}); score-=1
    if lm20 and lm50:
        if lm20>lm50: sigs.append({"ind":"MM50","msg":"MM20 > MM50 : Golden Cross haussier","sens":"positif"}); score+=1
        else: sigs.append({"ind":"MM50","msg":"MM20 < MM50 : Death Cross baissier","sens":"negatif"}); score-=1
    if lm200:
        if c>lm200: sigs.append({"ind":"MM200","msg":"Tendance longue terme haussiere (cours>MM200)","sens":"positif"}); score+=1
        else: sigs.append({"ind":"MM200","msg":"Tendance longue terme baissiere (cours<MM200)","sens":"negatif"}); score-=1
    lrsi=next((v for v in reversed(ind["rsi"]) if v is not None),None)
    if lrsi is not None:
        if lrsi<30: sigs.append({"ind":"RSI","msg":"RSI="+str(round(lrsi,1))+" : Survente - opportunite potentielle","sens":"positif"}); score+=2
        elif lrsi>70: sigs.append({"ind":"RSI","msg":"RSI="+str(round(lrsi,1))+" : Surachat - prudence recommandee","sens":"negatif"}); score-=2
        else: sigs.append({"ind":"RSI","msg":"RSI="+str(round(lrsi,1))+" : Zone neutre","sens":"neutre"})
    lm=next((v for v in reversed(ind["macd"]) if v is not None),None)
    ls=next((v for v in reversed(ind["signal"]) if v is not None),None)
    if lm is not None and ls is not None:
        if lm>ls: sigs.append({"ind":"MACD","msg":"MACD > Signal : momentum haussier","sens":"positif"}); score+=1
        else: sigs.append({"ind":"MACD","msg":"MACD < Signal : momentum baissier","sens":"negatif"}); score-=1
    lbu=next((v for v in reversed(ind["bb_upper"]) if v),None)
    lbl=next((v for v in reversed(ind["bb_lower"]) if v),None)
    if lbu and lbl:
        if c>lbu: sigs.append({"ind":"BB","msg":"Cours hors bande superieure : retour possible","sens":"negatif"}); score-=1
        elif c<lbl: sigs.append({"ind":"BB","msg":"Cours hors bande inferieure : rebond possible","sens":"positif"}); score+=1
        else: sigs.append({"ind":"BB","msg":"Cours dans les bandes de Bollinger","sens":"neutre"})
    # Stochastique
    lk=next((v for v in reversed(ind.get("stoch_k",[])) if v is not None),None)
    if lk is not None:
        if lk<20: sigs.append({"ind":"STOCH","msg":"Stochastique="+str(round(lk,1))+" : survente, rebond possible","sens":"positif"}); score+=1
        elif lk>80: sigs.append({"ind":"STOCH","msg":"Stochastique="+str(round(lk,1))+" : surachat, prudence","sens":"negatif"}); score-=1
        else: sigs.append({"ind":"STOCH","msg":"Stochastique="+str(round(lk,1))+" : zone neutre","sens":"neutre"})
    # Williams %R
    lw=next((v for v in reversed(ind.get("will_r",[])) if v is not None),None)
    if lw is not None:
        if lw<-80: sigs.append({"ind":"W%R","msg":"Williams %R="+str(round(lw,1))+" : survente","sens":"positif"}); score+=1
        elif lw>-20: sigs.append({"ind":"W%R","msg":"Williams %R="+str(round(lw,1))+" : surachat","sens":"negatif"}); score-=1
        else: sigs.append({"ind":"W%R","msg":"Williams %R="+str(round(lw,1))+" : zone neutre","sens":"neutre"})
    # ROC (momentum)
    lroc=next((v for v in reversed(ind.get("roc",[])) if v is not None),None)
    if lroc is not None:
        if lroc>3: sigs.append({"ind":"ROC","msg":"ROC=+"+str(round(lroc,1))+"% : momentum positif","sens":"positif"}); score+=1
        elif lroc<-3: sigs.append({"ind":"ROC","msg":"ROC="+str(round(lroc,1))+"% : momentum negatif","sens":"negatif"}); score-=1
        else: sigs.append({"ind":"ROC","msg":"ROC="+str(round(lroc,1))+"% : momentum faible","sens":"neutre"})
    if score>=4: v,vc="HAUSSIER","up"
    elif score<=-4: v,vc="BAISSIER","down"
    elif score>0: v,vc="PLUT. HAUSSIER","up"
    elif score<0: v,vc="PLUT. BAISSIER","down"
    else: v,vc="NEUTRE","neu"
    return {"signals":sigs,"verdict":v,"verdict_col":vc,"score":score,"score_max":10}

# ── Construction donnees par action ────────────────────────
def build_actions(pa, idx_ret=None):
    out={}
    idx_ret=idx_ret or {}
    for nom,ss in pa.items():
        cours=[s["close"] for s in ss]; vrs=[s["variation"] for s in ss]
        vls=[s["volume"] for s in ss]; n=len(ss)
        if n==0: continue
        mv=sum(vrs)/n; vol=sum((v-mv)**2 for v in vrs)/n
        volat=round(vol**0.5,2)
        trims=defaultdict(list)
        for s in ss:
            d=datetime.strptime(s["date"],"%Y-%m-%d")
            trims[str(d.year)+"-T"+str((d.month-1)//3+1)].append(s)
        trimestres=[]
        for cle in sorted(trims.keys()):
            ts=trims[cle]; o=ts[0]["close"]; c=ts[-1]["close"]
            trimestres.append({"label":cle,"open":o,"close":c,
                "perf":round((c-o)/o*100,2) if o else 0,
                "vol_moy":int(sum(s["volume"] for s in ts)/len(ts))})
        ic=cours.index(min(cours)); ix2=cours.index(max(cours))
        ind=calc_indicators(ss)
        interp=interpret(ss,ind)
        N=200  # nb points pour indicateurs

        # ── Indicateurs de risque derives ──
        # Rendements quotidiens de l action (par date, alignes avec MASI)
        asset_ret_par_date={}
        for i in range(1,n):
            if cours[i-1]:
                asset_ret_par_date[ss[i]["date"]]=(cours[i]-cours[i-1])/cours[i-1]*100
        # Beta vs MASI : aligner par date commune
        a_ret=[]; m_ret=[]
        for dte,r in asset_ret_par_date.items():
            if dte in idx_ret:
                a_ret.append(r); m_ret.append(idx_ret[dte])
        beta=calc_beta(a_ret,m_ret)
        # Sortino sur rendements quotidiens
        rets_q=list(asset_ret_par_date.values())
        sortino=calc_sortino(rets_q)
        # Volatilite annualisee (ecart-type quotidien * sqrt(252))
        vol_annual=round(volat*(252**0.5),2) if volat else None
        # Max drawdown
        maxdd=calc_max_drawdown(cours)
        # Fourchette 52 semaines (~252 dernieres seances)
        win52=ss[-252:] if n>=252 else ss
        c52=[s["close"] for s in win52]
        hi52=round(max(c52),2); lo52=round(min(c52),2)
        # Pivots sur la derniere seance (utilise high/low robustes)
        rh,rl=_hl_robuste(ss,14)
        pivots=calc_pivots(rh[-1],rl[-1],cours[-1])

        out[nom]={"dates":[s["date"] for s in ss],"cours":cours,
            "mins":[s["low"] for s in ss],"maxs":[s["high"] for s in ss],
            "vars":vrs,"vols":vls,
            "perf_totale":round((cours[-1]-cours[0])/cours[0]*100,2) if cours[0] else 0,
            "cours_min":min(cours),"cours_max":max(cours),
            "date_min":ss[ic]["date"],"date_max":ss[ix2]["date"],
            "vol_moy":int(sum(vls)/n),"volatilite":volat,
            "trimestres":trimestres,
            "meilleure":max(ss,key=lambda x:x["variation"]),
            "pire":     min(ss,key=lambda x:x["variation"]),
            "mm20":ind["mm20"][-N:],"mm50":ind["mm50"][-N:],
            "mm200":ind["mm200"][-N:],"rsi":ind["rsi"][-N:],
            "macd":ind["macd"][-N:],"macd_signal":ind["signal"][-N:],
            "macd_histo":ind["histogram"][-N:],
            "bb_upper":ind["bb_upper"][-N:],"bb_lower":ind["bb_lower"][-N:],
            "stoch_k":ind["stoch_k"][-N:],"stoch_d":ind["stoch_d"][-N:],
            "atr":ind["atr"][-N:],"obv":ind["obv"][-N:],
            "will_r":ind["will_r"][-N:],"roc":ind["roc"][-N:],"cci":ind["cci"][-N:],
            "beta":beta,"sortino":sortino,"vol_annual":vol_annual,"maxdd":maxdd,
            "hi52":hi52,"lo52":lo52,"pivots":pivots,
            "interp":interp,
            "candle_dates":[s["date"] for s in ss[-90:]],
            "candle_open": [s["close"] for s in ss[-90:]],
            "candle_close":[s["close"] for s in ss[-90:]],
            "candle_high": [s["high"]  for s in ss[-90:]],
            "candle_low":  [s["low"]   for s in ss[-90:]]}
    return out

# ── Construction donnees par date ──────────────────────────
def build_dates(pa,ix):
    pd_=defaultdict(list)
    for nom,ss in pa.items():
        for s in ss:
            pd_[s["date"]].append({"nom":nom,"value":s["close"],"min":s["low"],
                "max":s["high"],"variation":s["variation"],"volume":s["volume"],
                "montant":round(s["close"]*s["volume"],2)})
    dates=sorted(pd_.keys()); summ={}
    for d in dates:
        its=pd_[d]
        if not its: continue
        summ[d]={"masi":ix.get(d,{}).get("MASI"),"msi20":ix.get(d,{}).get("MSI20"),
            "nb_h":sum(1 for i in its if i["variation"]>0),
            "nb_b":sum(1 for i in its if i["variation"]<0),
            "nb_s":sum(1 for i in its if i["variation"]==0),
            "vol_total":sum(i["volume"] for i in its),
            "mnt_total":sum(i["montant"] for i in its),
            "top5_h":sorted(its,key=lambda x:x["variation"],reverse=True)[:5],
            "top5_b":sorted(its,key=lambda x:x["variation"])[:5],
            "top5_v":sorted(its,key=lambda x:x["volume"],reverse=True)[:5],
            "top5_m":sorted(its,key=lambda x:x["montant"],reverse=True)[:5]}
    return dates,summ

# ── Calcul scores ──────────────────────────────────────────
def build_stats(pa, idx_ret=None):
    stats={}; idx_ret=idx_ret or {}
    for nom,ss in pa.items():
        if len(ss)<10: continue
        cours=[s["close"] for s in ss]; vols=[s["volume"] for s in ss]
        vars_=[s["variation"] for s in ss]; n=len(ss)
        perf=(cours[-1]-cours[0])/cours[0]*100 if cours[0] else 0
        vm=sum(vars_)/n; volat=(sum((v-vm)**2 for v in vars_)/n)**0.5
        mid=max(1,n-30); cr=sum(cours[mid:])/len(cours[mid:])
        ca=sum(cours[max(0,mid-30):mid])/max(1,len(cours[max(0,mid-30):mid]))
        tend=(cr-ca)/ca*100 if ca else 0
        sharpe=vm/volat if volat>0 else 0
        rpos=sum(1 for v in vars_ if v>0)/n*100
        # Indicateurs de risque derives
        a_ret=[]; m_ret=[]
        for i in range(1,n):
            if cours[i-1]:
                r=(cours[i]-cours[i-1])/cours[i-1]*100
                if ss[i]["date"] in idx_ret:
                    a_ret.append(r); m_ret.append(idx_ret[ss[i]["date"]])
        beta=calc_beta(a_ret,m_ret)
        rets_q=[(cours[i]-cours[i-1])/cours[i-1]*100 for i in range(1,n) if cours[i-1]]
        sortino=calc_sortino(rets_q)
        maxdd=calc_max_drawdown(cours)
        vol_annual=round(volat*(252**0.5),2) if volat else None
        score=min(25,max(0,perf/2))+min(25,max(0,tend*2))
        score+=((rpos-50)*0.4 if rpos>50 else 0)+min(15,max(0,sharpe*50))+min(15,max(0,(2-volat)*7.5))
        score=round(max(0,min(100,score)),1)
        if score>=60 and tend>0: sig,sigc="ACHAT","up"
        elif score<=25 or tend<-3: sig,sigc="PRUDENCE","down"
        else: sig,sigc="NEUTRE","neu"
        stats[nom]={"cours_actuel":cours[-1],"cours_depart":cours[0],
            "perf_totale":round(perf,2),"vol_moyen":int(sum(vols)/n),
            "vol_total":sum(vols),"var_moy":round(vm,3),
            "volatilite":round(volat,2),"tendance":round(tend,2),
            "sharpe":round(sharpe,3),"ratio_pos":round(rpos,1),
            "beta":beta,"sortino":sortino,"maxdd":maxdd,"vol_annual":vol_annual,
            "nb_seances":n,"score":score,"signal":sig,"signal_couleur":sigc,
            "date_debut":ss[0]["date"],"date_fin":ss[-1]["date"]}
    return stats


# Template HTML embarque
_TEMPLATE_B64_CONST = ""
# ── MAIN ──────────────────────────────────────────────────
def main():
    print("\n"+SEP+"\n  SCRIPT 3 - Generation du dashboard HTML\n"+SEP)
    print("  Lecture : "+str(CSV_PATH))
    if not CSV_PATH.exists():
        print("  ERREUR : "+str(CSV_PATH)+" introuvable."); sys.exit(1)

    pa=defaultdict(list); ix=defaultdict(dict)
    with open(str(CSV_PATH),encoding="utf-8-sig",newline="") as f:
        for row in csv.DictReader(f):
            nom=row["Action"].strip()
            if nom in ("MASI","MSI20"):
                ds=row["index"].strip()
                if ds:
                    try: ix[ds][nom]=float(row["Value"])
                    except: pass
                continue
            ds=row["Date"].strip()
            if not ds: continue
            try:
                val=float(row["Value"])
                pa[nom].append({"date":ds,"close":val,
                    "high": float(row["Max"]) if row["Max"].strip() else val,
                    "low":  float(row["Min"]) if row["Min"].strip() else val,
                    "volume":int(float(row["Volume"])) if row["Volume"].strip() else 0,
                    "variation":float(row["Variation"])})
            except: pass
    for n in pa: pa[n].sort(key=lambda x:x["date"])
    log(str(len(pa))+" actions chargees")

    # Rendements quotidiens du MASI (pour le calcul du beta des actions)
    masi_serie=sorted((d,v["MASI"]) for d,v in ix.items() if v.get("MASI"))
    idx_ret={}
    for i in range(1,len(masi_serie)):
        d0,v0=masi_serie[i-1]; d1,v1=masi_serie[i]
        if v0: idx_ret[d1]=(v1-v0)/v0*100

    # Repli : si le MASI n est pas renseigne (cas frequent : lignes index
    # vides dans le CSV), on construit un indice de marche EQUIPONDERE a
    # partir de la variation moyenne de toutes les actions chaque jour.
    if len(idx_ret) < 50:
        from collections import defaultdict as _dd
        par_date=_dd(list)
        for nom,ss in pa.items():
            for s in ss:
                par_date[s["date"]].append(s["variation"])
        proxy={d:(sum(v)/len(v)) for d,v in par_date.items() if v}
        idx_ret=proxy
        log("MASI non renseigne -> indice de marche equipondere utilise pour le beta ("+str(len(idx_ret))+" seances)")
    else:
        log(str(len(idx_ret))+" rendements MASI disponibles (calcul du beta actif)")

    log("Calcul indicateurs techniques (MM, RSI, MACD, BB, Stoch, ATR, OBV, W%R, ROC, CCI) ...")
    ad=build_actions(pa, idx_ret)
    log("Construction donnees dates ...")
    dates,summ=build_dates(pa,ix)
    log("Calcul scores, risque (beta, Sortino, drawdown) et recommandations ...")
    stats=build_stats(pa, idx_ret)
    log(str(len(dates))+" seances | derniere : "+(dates[-1] if dates else "?"))

    masi_last=""
    for d in reversed(sorted(ix.keys())):
        v=ix[d].get("MASI")
        if v: masi_last="{:.2f}".format(v); break

    gen_time=datetime.now().strftime("%d/%m/%Y %H:%M")
    last_date=datetime.strptime(dates[-1],"%Y-%m-%d").strftime("%d/%m/%Y") if dates else ""

    # Charger les fondamentaux si disponibles
    fond_path = DOSSIER / "fondamentaux.json"
    if fond_path.exists():
        log("Chargement des fondamentaux ...")
        with open(str(fond_path), encoding="utf-8") as ff:
            fond = json.load(ff)
        log(str(len(fond)) + " actions avec donnees fondamentales.")
    else:
        fond = {}
        log("fondamentaux.json absent - donnees fondamentales vides.")

    sep=(",",":")
    aj=json.dumps({"actions":ad,"action_names":sorted(ad.keys()),
                   "masi":sorted(ix.items()),"stats":stats},separators=sep)
    dj=json.dumps({"dates":dates,"summaries":summ},separators=sep)

    # Charger le template (embarque dans ce script)
    import base64 as _b64
    html = _b64.b64decode(_TEMPLATE_B64_CONST).decode('utf-8')
    # Optionnel : si bourse_template.html existe, l utiliser a la place
    tpl = DOSSIER / "bourse_template.html"
    if tpl.exists():
        with open(str(tpl), encoding="utf-8") as f: html = f.read()

    fond_json = json.dumps(fond or {}, separators=sep, ensure_ascii=False)
    html=html.replace("%%ACTION_DATA%%",aj)
    html=html.replace("%%DATE_DATA%%",dj)
    html=html.replace("%%FOND_DATA%%",fond_json)
    html=html.replace("%%GEN_TIME%%",gen_time)
    html=html.replace("%%LAST_DATE%%",last_date)
    html=html.replace("%%MASI_VAL%%",masi_last)

    with open(str(HTML_PATH),"w",encoding="utf-8") as f: f.write(html)
    taille=os.path.getsize(str(HTML_PATH))//1024
    print("  [OK] "+str(HTML_PATH)+" ("+str(taille)+" KB)")
    print(SEP+"\n")

if __name__=="__main__":
    try:
        main()
    except Exception as e:
        import traceback
        print("")
        print("=" * 62)
        print("  ERREUR FATALE :")
        print("  " + str(e))
        print("")
        print("  Detail complet :")
        traceback.print_exc()
        print("=" * 62)
        input("  Appuyez sur Entree pour fermer...")
